-- ----------------------------------------------------------------------------
-- vw_profiles: Per-user settings, one row per user. Holds the gentle parameters that drive the daily ritual. This is the ownership root: every owned row points back here through its Owner relationship.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_profiles WITH (security_invoker = ON) AS
SELECT
  t.profiles_id,                                                                -- Primary key (auto-synthesized: Profiles had no field named 'Id' or ending in 'Id').
  calc_profiles_name(t.profiles_id) AS name,                                    -- Logical key for the profile, a slug of the account key. Maps to the per-user identity in the substrate.
  t.account_key,                                                                -- Stable per-user identity key. Maps to user_id in the generated schema. Owned rows reference this value through their Owner relationship.
  t.display_name,                                                               -- Friendly display name shown in the app. Default Liz. Maps to profile.display_name.
  t.tagline,                                                                    -- Personal tagline. Default Illuminating Life, Legacy, and Love. Maps to profile.tagline.
  t.weekly_warmup_goal,                                                         -- Target number of hellos per week, shown as encouragement, never a backlog. Default 4. Maps to profile.weekly_warmup_goal. See GovernanceRules R4.
  t.warm_threshold_days,                                                        -- A person stays Warm within this many days of the last hello. Default 14. Maps to profile.warm_threshold_days. See GovernanceRules R2.
  t.cooling_threshold_days,                                                     -- A person is Cooling up to this many days since the last hello, then Cold beyond it. Default 30. Maps to profile.cooling_threshold_days. See GovernanceRules R2.
  t.morning_warmup_count,                                                       -- How many people the Today screen surfaces each morning, one at a time. Default 3. Maps to profile.morning_warmup_count. See GovernanceRules R3.
  t.week_start,                                                                 -- Anchor for the weekly count, set to the most recent Monday. Maps to profile.week_start. See GovernanceRules R4.
  t.week_count,                                                                 -- Hellos logged since WeekStart, maintained by the app and reset each Monday. Default 0. Maps to profile.week_count.
  t.people,                                                                     -- The people owned by this profile.
  t.facilities,                                                                 -- The facilities owned by this profile.
  t.captures,                                                                   -- The captures owned by this profile.
  t.o_auth_tokens,                                                              -- The server-side OAuth tokens owned by this profile.
  calc_profiles_count_of_people(t.profiles_id) AS count_of_people,              -- Number of people in this profile's warm network.
  calc_profiles_count_of_facilities(t.profiles_id) AS count_of_facilities,      -- Number of target facilities owned by this profile.
  calc_profiles_count_of_captures(t.profiles_id) AS count_of_captures           -- Number of captures owned by this profile.
FROM profiles t;

-- ----------------------------------------------------------------------------
-- vw_people: The warm network. Liz's sphere of influence and community ecosystem, anyone who can open a door or help map who is aligned.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_people WITH (security_invoker = ON) AS
SELECT
  t.people_id,                                                                  -- Primary key (auto-synthesized: People had no field named 'Id' or ending in 'Id').
  calc_people_name(t.people_id) AS name,                                        -- Logical key for the person, a slug of FullName.
  t.full_name,                                                                  -- The person's name. The only required field on a person. Maps to people.name. See GovernanceRules R6.
  t.owner,                                                                      -- The profile that owns this row. Holds the Profiles Name. Drives Row Level Security. Maps to people.user_id. See GovernanceRules R1.
  t.role_org,                                                                   -- The person's role or organization. Maps to people.role_org.
  t.sphere,                                                                     -- Which sphere of the network this person belongs to. Holds the Spheres Name. Maps to people.sphere.
  t.relationship,                                                               -- How Liz knows this person, in her own words. Maps to people.relationship.
  t.doors_can_open,                                                             -- What doors this person can open or who they can introduce. Maps to people.doors_can_open.
  t.the_ask,                                                                    -- The specific ask or next favor, kept human and light. Maps to people.the_ask.
  t.email,                                                                      -- Email address, used by the native email compose link. Maps to people.email.
  t.phone,                                                                      -- Phone number. Maps to people.phone.
  t.linkedin_url,                                                               -- LinkedIn profile URL, used only for Open in LinkedIn deep links. Maps to people.linkedin_url. See GovernanceRules R10.
  t.status,                                                                     -- Where this relationship stands. Holds the PersonStatuses Name. Defaults to to-reach-out. Maps to people.status.
  t.last_touched,                                                               -- Date of the most recent hello. Logging a hello sets this to today. Drives Warmth. Maps to people.last_touched. See GovernanceRules R2 and R3.
  t.next_step,                                                                  -- The gentle next step with this person. Maps to people.next_step.
  t.notes,                                                                      -- Free notes. Maps to people.notes.
  calc_people_warm_threshold_days(t.people_id) AS warm_threshold_days,          -- The owner's warm threshold in days, pulled from the owning profile. Falls back to 14 when the profile leaves it blank, so a missing threshold never silently turns every contact cold.
  calc_people_cooling_threshold_days(t.people_id) AS cooling_threshold_days,    -- The owner's cooling threshold in days, pulled from the owning profile. Falls back to 30 when the profile leaves it blank.
  calc_people_days_since_last_touched(t.people_id) AS days_since_last_touched,  -- Days since the last hello, or 0 when never touched. Time relative, resolved at view-compute time. ISBLANK guards the unset (NULL) date.
  calc_people_is_never_touched(t.people_id) AS is_never_touched,                -- True when there is no recorded hello yet. A never touched contact reads as ready for a hello, never as overdue. See GovernanceRules R5.
  calc_people_warmth(t.people_id) AS warmth                                     -- Derived warmth: warm within WarmThresholdDays, cooling up to CoolingThresholdDays, otherwise cold, including never touched. Matches a WarmthLevels Name. Drives sorting and the daily ritual only. See GovernanceRules R2.
FROM people t;

-- ----------------------------------------------------------------------------
-- vw_facilities: The target places. Values aligned independent living and 55 and over communities first, the places Liz is working toward.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_facilities WITH (security_invoker = ON) AS
SELECT
  t.facilities_id,                                                              -- Primary key (auto-synthesized: Facilities had no field named 'Id' or ending in 'Id').
  calc_facilities_name(t.facilities_id) AS name,                                -- Logical key for the facility, a slug of FacilityName.
  t.facility_name,                                                              -- The facility name. The only required field on a facility. Maps to facilities.facility_name. See GovernanceRules R6.
  t.owner,                                                                      -- The profile that owns this row. Holds the Profiles Name. Drives Row Level Security. Maps to facilities.user_id. See GovernanceRules R1.
  t.type,                                                                       -- The kind of facility. Holds the FacilityTypes Name. Maps to facilities.type.
  t.town,                                                                       -- Town where the facility is located. Maps to facilities.town.
  t.region,                                                                     -- Region grouping for the facility. Holds the Regions Name. Maps to facilities.region.
  t.lead_route,                                                                 -- How Liz can reach this facility, warm or cold. Holds the LeadRoutes Name. Maps to facilities.lead_route.
  t.aligned,                                                                    -- Whether the facility seems values aligned. Holds the AlignmentLevels Name. Maps to facilities.aligned.
  t.decision_maker,                                                             -- Name of the person who decides. Maps to facilities.decision_maker.
  t.title,                                                                      -- Title of the decision maker. Maps to facilities.title.
  t.email,                                                                      -- Contact email. Maps to facilities.email.
  t.phone,                                                                      -- Contact phone. Maps to facilities.phone.
  t.website,                                                                    -- Facility website. Maps to facilities.website.
  t.status,                                                                     -- Where the outreach stands. Holds the FacilityStatuses Name. Defaults to to-research. Maps to facilities.status.
  t.next_step,                                                                  -- The gentle next step with this facility. Maps to facilities.next_step.
  t.fit_notes,                                                                  -- Notes on fit and alignment. Maps to facilities.fit_notes.
  calc_facilities_region_label(t.facilities_id) AS region_label,                -- Human readable region label, pulled from the related region.
  calc_facilities_lead_route_label(t.facilities_id) AS lead_route_label,        -- Human readable lead route label, pulled from the related lead route.
  calc_facilities_is_warm_lead(t.facilities_id) AS is_warm_lead                 -- True when there is a warm route into this facility rather than a cold approach.
FROM facilities t;

