  calc_captures_name(t.captures_id) AS name,                                    -- Logical key for the capture, a slug of Title.
  t.title,                                                                      -- Short title of the capture. The only required field on a capture. Maps to captures.title. See GovernanceRules R6.
  t.owner,                                                                      -- The profile that owns this row. Holds the Profiles Name. Drives Row Level Security. Maps to captures.user_id. See GovernanceRules R1.
