-- ----------------------------------------------------------------------------
-- vw_o_auth_tokens: Server-side storage for Drive, LinkedIn, and optional Calendar and Gmail tokens. Never exposed to the client. Read and refreshed only in server code. See GovernanceRules R12.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_o_auth_tokens WITH (security_invoker = ON) AS
SELECT
  t.o_auth_tokens_id,                                                           -- Primary key (auto-synthesized: OAuthTokens had no field named 'Id' or ending in 'Id').
  calc_o_auth_tokens_name(t.o_auth_tokens_id) AS name,                          -- Logical key for the token, a compound of owner and provider.
  t.owner,                                                                      -- The profile that owns this token. Holds the Profiles Name. Maps to oauth_tokens.user_id. See GovernanceRules R1.
  t.provider,                                                                   -- The integration this token is for, for example google-drive, linkedin, google-calendar, or gmail. Maps to oauth_tokens.provider.
  t.access_token,                                                               -- Short lived access token. Server-side only, never sent to the client. Maps to oauth_tokens.access_token. See GovernanceRules R12.
  t.refresh_token,                                                              -- Long lived refresh token, stored encrypted and tied to the owner. Server-side only. Maps to oauth_tokens.refresh_token. See GovernanceRules R12.
  t.scope,                                                                      -- The granted OAuth scope, kept as narrow as the feature needs. Maps to oauth_tokens.scope. See GovernanceRules R11.
  t.expires_at                                                                  -- When the access token expires. Maps to oauth_tokens.expires_at.
FROM o_auth_tokens t;

