-- ----------------------------------------------------------------------------
-- vw_warmth_levels: Controlled vocabulary for the derived warmth value. Warmth is computed from LastTouched and is not stored. These rows give the frontend the labels and gentle framing for each level. See GovernanceRules R2 and R5.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_warmth_levels WITH (security_invoker = ON) AS
SELECT
  t.warmth_levels_id,                                                           -- Primary key (auto-synthesized: WarmthLevels had no field named 'Id' or ending in 'Id').
  calc_warmth_levels_name(t.warmth_levels_id) AS name,                          -- Slug key for the warmth level, derived from the label. Matches the value returned by People.Warmth.
  t.warmth_label,                                                               -- Human readable warmth label shown in the app.
  t.description,                                                                -- What this warmth level means.
  t.guidance,                                                                   -- Gentle framing shown to Liz. No guilt, a cold contact reads as ready for a hello. See GovernanceRules R5.
  t.sort_order                                                                  -- Display order, warmest first.
FROM warmth_levels t;

-- ----------------------------------------------------------------------------
-- vw_governance_rules: The governance rules for the BeaconHaus Companion, one row per rule. Each rule is meaning that lives in the rulebook and is traceable. The frontend and backend enforce these because they are generated from them, not because someone wrote them into code by hand.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_governance_rules WITH (security_invoker = ON) AS
SELECT
  t.governance_rules_id,                                                        -- Primary key (auto-synthesized: GovernanceRules had no field named 'Id' or ending in 'Id').
  calc_governance_rules_name(t.governance_rules_id) AS name,                    -- Slug key for the rule, derived from the title.
  t.rule_code,                                                                  -- Short rule code, R1 through R12.
  t.title,                                                                      -- Short title of the rule.
  t.statement,                                                                  -- The full rule statement, the meaning that downstream artifacts must honor.
  t.category,                                                                   -- Grouping for the rule, for example Ownership, Warmth, Ritual, Content, Positioning, Integration, Security, or UX.
  t.enforced_by,                                                                -- Where this rule is realized in the derivative outputs.
  t.sort_order                                                                  -- Display order, R1 through R12.
FROM governance_rules t;

